NDARD_ACCT_HEAD_B.N_STD_ACCT_HEAD_SKEY  WHEN SIGNFCNT_INVSTMNT.V_CAP_COMP_GROUP_CODE = 'T2COMP' THEN  DIM_STANDARD_ACCT_HEAD_C.N_STD_ACCT_HEAD_SKEY  END,SIGNFCNT_INVSTMNT.N_STD_ACCT_HEAD_SKEY,SIGNFCNT_INVSTMNT.N_UNDRAWN_AMOUNT,SIGNFCNT_INVSTMNT.N_UNDRAWN_EAD_PRE_MITIGATION,SIGNFCNT_INVSTMNT.N_UNPAID_PREMIUM,SIGNFCNT_INVSTMNT.N_VALUATION_ADJ_AMOUNT FROM ( SELECT FSI_CAP_INVESTMENT_EXPOSURES.N_RUN_SKEY, FSI_CAP_INVESTMENT_EXPOSURES.N_MIS_DATE_SKEY, FSI_CAP_INVESTMENT_EXPOSURES.N_ACCT_SKEY, FSI_CAP_INVESTMENT_EXPOSURES.N_GAAP_SKEY, FSI_CAP_INVESTMENT_EXPOSURES.N_STD_ACCT_HEAD_SKEY, FSI_CAP_INVESTMENT_EXPOSURES.N_CAP_COMP_GROUP_SKEY, FSI_CAP_INVESTMENT_EXPOSURES.N_EXP_DED_AMT, FSI_CAP_INVESTMENT_EXPOSURES.N_DRAWN_EAD_PRE_MITIGATION, NULL N_DVA_AMOUNT, FSI_CAP_INVESTMENT_EXPOSURES.N_EAD_PRE_MITIGATION, FSI_CAP_INVESTMENT_EXPOSURES.N_EL_AMOUNT, FSI_CAP_INVESTMENT_EXPOSURES.N_EXP_COVERED_AMT, FSI_CAP_INVESTMENT_EXPOSURES.N_EXP_MTM_VALUE, NULL N_INCURRED_CVA_AMOUNT, FSI_CAP_INVESTMENT_EXPOSURES.N_INSTR_OTH_VALUATION_ADJ_AMT, FSI_CAP_INVESTMENT_EXPOSURES.N_INSTR_VALUATION_ADJ_AMOUNT, NULL N_NOTIONAL_PRINCIPAL, NULL N_OTC_DERIVATIVE_MULTIPLIER, FSI_CAP_INVESTMENT_EXPOSURES.N_OTHER_VALUATION_ADJ_AMT, FSI_CAP_INVESTMENT_EXPOSURES.N_PRE_CRM_POST_VOL_HC_EAD, FSI_CAP_INVESTMENT_EXPOSURES.N_PRE_MITIGATION_CAPITAL_UL, FSI_CAP_INVESTMENT_EXPOSURES.N_PRE_MITIGATION_EL_AMT, FSI_CAP_INVESTMENT_EXPOSURES.N_PRE_MITIGATION_RWA_UL, FSI_CAP_INVESTMENT_EXPOSURES.N_PROVISION_AMOUNT, FSI_CAP_INVESTMENT_EXPOSURES.N_RWA_UL_AMT, NULL N_UNPAID_PREMIUM, FSI_CAP_INVESTMENT_EXPOSURES.N_VALUATION_ADJ_AMOUNT, FSI_CAP_INVESTMENT_EXPOSURES.N_EXPOSURE_AMOUNT, FSI_CAP_INVESTMENT_EXPOSURES.N_LEVERAGE_EXPOSURE_AMOUNT, FSI_CAP_INVESTMENT_EXPOSURES.N_POTENTIAL_ESTIMATE_LOSS, FSI_CAP_INVESTMENT_EXPOSURES.N_UNDRAWN_AMOUNT, FSI_CAP_INVESTMENT_EXPOSURES.N_UNDRAWN_EAD_PRE_MITIGATION, DIM_CAPITAL_COMP_GROUP.V_CAP_COMP_GROUP_CODE FROM FSI_CAP_INVESTMENT_EXPOSURES INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = FSI_CAP_INVE